<div class="panel"><h1><?= __('invoices') ?></h1><p><a class="btn" href="index.php?route=invoice/create"><?= __('create') ?></a></p><table id="invoices-table" class="data-table"><thead><tr><th>ID</th><th><?= __('email') ?></th><th><?= __('products') ?></th><th><?= __('date') ?></th><th><?= __('quantity') ?></th><th><?= __('total') ?></th><th><?= __('actions') ?></th></tr></thead><tbody><?php foreach($invoices as $i): ?><tr><td><?= $i['id'] ?></td><td><?= htmlspecialchars($i['user_email']) ?></td><td><?= htmlspecialchars($i['product_name']) ?></td><td><?= htmlspecialchars($i['invoice_date']) ?></td><td><?= $i['quantity'] ?></td><td><?= number_format((float)$i['total_amount'],2) ?></td><td><a href="index.php?route=invoice/edit&id=<?= $i['id'] ?>"><?= __('edit') ?></a><form method="post" action="index.php?route=invoice/delete" style="display:inline" onsubmit="return confirm('Delete?')"><input type="hidden" name="id" value="<?= $i['id'] ?>"><button class="link-button"><?= __('delete') ?></button></form></td></tr><?php endforeach; ?></tbody></table><?php require VIEWS_DIR.'/_pagination.php'; ?></div>
